pub fn end_hidden_input_attrs(&self) -> AttrMap {
    let mut attrs = AttrMap::new();
    attrs.set(HtmlAttr::Type, "hidden");
    if let Some(name) = &self.ctx.end_name {
        attrs.set(HtmlAttr::Name, name);
