/// State machine for the `DateRangeField` component.
#[derive(Debug)]
pub struct Machine;

impl ars_core::Machine for Machine {
    type State = State;
    type Event = Event;
    type Context = Context;
    type Props = Props;
    type Messages = Messages;
    type Effect = NoEffect;
    type Api<'a> = Api<'a>;

    fn init(
        props: &Self::Props,
        env: &Env,
        messages: &Self::Messages,
    ) -> (Self::State, Self::Context) {
        let value = if let Some(value) = &props.value {
            Bindable::controlled(value.clone())
        } else {
            Bindable::uncontrolled(props.default_value.clone())
        };

        let initial_range = value.get().clone();
        let start_date = initial_range.as_ref().map(|range| range.start.clone());
        let end_date = initial_range.as_ref().map(|range| range.end.clone());

        let ctx = Context {
            value,
            start_date,
            end_date,
            active_field: None,
            min: props.min.clone(),
            max: props.max.clone(),
            locale: env.locale.clone(),
            intl_backend: Arc::clone(&env.intl_backend),
            messages: messages.clone(),
            disabled: props.disabled,
            readonly: props.readonly,
            required: props.required,
            name: props.name.clone(),
            start_name: props.start_name.clone(),
            end_name: props.end_name.clone(),
            ids: ComponentIds::from_id(&props.id),
            has_description: props.has_description,
            has_error_message: props.has_error_message,
            force_leading_zeros: props.force_leading_zeros,
        };

        (State::Idle, ctx)
    }

    fn transition(
        _state: &Self::State,
        event: &Self::Event,
        ctx: &Self::Context,
        _props: &Self::Props,
    ) -> Option<TransitionPlan<Self>> {
        // `SyncProps` must process even when disabled so adapter-driven prop
        // updates (including re-enabling) still reach the context.
        if ctx.disabled && !matches!(event, Event::SyncProps(_)) {
            return None;
        }

        match event {
            Event::SyncProps(props) => {
                let props = props.as_ref().clone();
                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
                    sync_props(ctx, &props);
                }))
            }

            Event::FocusStart => Some(TransitionPlan::to(State::StartFocused).apply(
                |ctx: &mut Context| {
                    ctx.active_field = Some(ActiveField::Start);
                },
            )),

            Event::FocusEnd => Some(TransitionPlan::to(State::EndFocused).apply(
                |ctx: &mut Context| {
                    ctx.active_field = Some(ActiveField::End);
                },
            )),

            Event::BlurAll => Some(TransitionPlan::to(State::Idle).apply(|ctx: &mut Context| {
                ctx.active_field = None;
            })),

            Event::SetRange(range) => {
                if ctx.readonly {
                    return None;
                }

                let range = range.clone();
                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
                    ctx.start_date = range.as_ref().map(|range| range.start.clone());
                    ctx.end_date = range.as_ref().map(|range| range.end.clone());
                    ctx.value.set(range);
                }))
            }

            Event::StartValueChange(date) => {
                if ctx.readonly {
                    return None;
                }

                let date = date.clone();
                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
                    apply_start_change(ctx, date);
                }))
            }

            Event::EndValueChange(date) => {
                if ctx.readonly {
                    return None;
                }

                let date = date.clone();
                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
                    apply_end_change(ctx, date);
                }))
            }
        }
    }

    fn on_props_changed(old: &Self::Props, new: &Self::Props) -> Vec<Self::Event> {
        debug_assert_eq!(
            old.id, new.id,
            "date_range_field::Props.id must remain stable after init"
        );

        if old == new {
            Vec::new()
        } else {
            vec![Event::SyncProps(Box::new(new.clone()))]
        }
    }

    fn connect<'a>(
        state: &'a Self::State,
        ctx: &'a Self::Context,
        props: &'a Self::Props,
        send: &'a dyn Fn(Self::Event),
    ) -> Self::Api<'a> {
        Api::new(state, ctx, props, send)
    }
}

/// Re-derives mutable context fields from changed props.
///
/// `id` is fixed at construction (see [`Machine::on_props_changed`]). For a
/// controlled component (`props.value` is `Some`) the controlled override and
/// the per-field working values are reconciled to the new range; an
/// uncontrolled component keeps its internal working state and merely drops any
/// stale controlled override.
fn sync_props(ctx: &mut Context, props: &Props) {
    ctx.min = props.min.clone();
    ctx.max = props.max.clone();
    ctx.disabled = props.disabled;
    ctx.readonly = props.readonly;
    ctx.required = props.required;
    ctx.name = props.name.clone();
    ctx.start_name = props.start_name.clone();
    ctx.end_name = props.end_name.clone();
    ctx.has_description = props.has_description;
    ctx.has_error_message = props.has_error_message;
    ctx.force_leading_zeros = props.force_leading_zeros;

    if let Some(controlled) = &props.value {
        ctx.value.sync_controlled(Some(controlled.clone()));
        ctx.start_date = controlled.as_ref().map(|range| range.start.clone());
        ctx.end_date = controlled.as_ref().map(|range| range.end.clone());
    } else {
        ctx.value.sync_controlled(None);
    }
}

/// Applies a start-date change, then recomputes the derived range.
fn apply_start_change(ctx: &mut Context, start: Option<CalendarDate>) {
    ctx.start_date = start;

    recompute_range(ctx);
}

/// Applies an end-date change, then recomputes the derived range.
fn apply_end_change(ctx: &mut Context, end: Option<CalendarDate>) {
    ctx.end_date = end;

    recompute_range(ctx);
}

/// Recomputes the derived complete range from the two field values.
///
/// When both fields hold a value the range is normalized (swapping if needed so
/// `start <= end`) and the normalized order is reflected back into the field
/// values. When either field is empty the range is incomplete and the value is
/// cleared.
fn recompute_range(ctx: &mut Context) {
    match (ctx.start_date.clone(), ctx.end_date.clone()) {
        (Some(start), Some(end)) => match DateRange::normalized(start, end) {
            Some(range) => {
                ctx.start_date = Some(range.start.clone());
                ctx.end_date = Some(range.end.clone());
                ctx.value.set(Some(range));
            }

            // The two dates are not comparable (e.g. different calendars/eras
            // supplied via the public setters); clear the derived range rather
            // than leave a stale value behind the new field values.
            None => ctx.value.set(None),
        },

        _ => ctx.value.set(None),
    }
}

