        if self.ctx.readonly {
            attrs
                .set_bool(HtmlAttr::Data("ars-readonly"), true)
                .set(HtmlAttr::Aria(AriaAttr::ReadOnly), "true");
        }

        if self.ctx.required {
            attrs.set(HtmlAttr::Aria(AriaAttr::Required), "true");
