/// free of closures.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct Preset {
    /// The pre-localized label shown on the preset trigger.
    pub label: String,
    /// The concrete range applied when this preset is selected.
    pub range: DateRange,
}
